1	type Quote = { premium: number };
2	type Item = {
3	  type: string;
4	  material?: string;
5	  cursed?: boolean;
6	  enchantment?: number;
7	};
8	type QuoteInput = {
9	  customer?: { yearsWithMHPCO: number };
10	  firstInsurance?: boolean;
11	  followUp?: boolean;
12	  items: Item[];
13	};
14	
15	const PROCESSING_FEE = 5;
16	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
17	  sword: 100,
18	  staff: 80,
19	  amulet: 60,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	const ALIKE_BLOCK_SIZE = 3;
25	const ALIKE_BLOCK_PREMIUM = 60;
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	const basePremiumFor = (item: Item): number => {
35	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
36	  if (basePremium === undefined) {
37	    throw new Error(`Unknown item type: ${item.type}`);
38	  }
39	  return basePremium;
40	};
41	
42	const curseSurchargeRateFor = (item: Item): number =>
43	  item.cursed ? CURSE_SURCHARGE_RATE : 0;
44	
45	const enchantmentSurchargeRateFor = (item: Item): number =>
46	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
47	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE
48	    : 0;
49	
50	const totalSurchargeRateFor = (item: Item): number =>
51	  curseSurchargeRateFor(item) + enchantmentSurchargeRateFor(item);
52	
53	const itemPremiumFor = (item: Item): number =>
54	  basePremiumFor(item) * (1 + totalSurchargeRateFor(item));
55	
56	const sumBy = <T>(items: T[], valueFn: (item: T) => number): number =>
57	  items.reduce((sum, item) => sum + valueFn(item), 0);
58	
59	const sumItemPremiums = (items: Item[]): number => sumBy(items, itemPremiumFor);
60	
61	const isAlikeBlock = (items: Item[]): boolean =>
62	  items.length === ALIKE_BLOCK_SIZE &&
63	  items.every((item) => item.type === items[0].type);
64	
65	const componentsPremium = (items: Item[]): number =>
66	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
67	
68	const loyaltyDiscountRateFor = (input: QuoteInput): number =>
69	  (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD
70	    ? LOYALTY_DISCOUNT_RATE
71	    : 0;
72	
73	const firstInsuranceSurchargeRateFor = (input: QuoteInput): number =>
74	  input.firstInsurance ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
75	
76	const followUpDiscountRateFor = (input: QuoteInput): number =>
77	  input.followUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
78	
79	const policyAdjustmentRateFor = (input: QuoteInput): number =>
80	  firstInsuranceSurchargeRateFor(input) -
81	  loyaltyDiscountRateFor(input) -
82	  followUpDiscountRateFor(input);
83	
84	export const quote = (input: QuoteInput): Quote => {
85	  const componentsTotal = componentsPremium(input.items);
86	  const policyTotal = componentsTotal + componentsTotal * policyAdjustmentRateFor(input);
87	  return { premium: Math.ceil(policyTotal + PROCESSING_FEE) };
88	};
89	
90	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
91	  sword: 1000,
92	  amulet: 600,
93	  staff: 800,
94	  potion: 400,
95	  rune: 250,
96	  moonstone: 250,
97	};
98	const DEDUCTIBLE = 100;
99	const FULL_REIMBURSEMENT_RATE = 1;
100	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
101	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
102	const CAP_MULTIPLIER = 2;
103	
104	type Damage = { itemType: string; amount: number };
105	type ClaimInput = {
106	  policy: { items: Item[] };
107	  incident: { damages: Damage[] };
108	};
109	type ClaimResult = { payout: number; remainingCap: number };
110	
111	const reimbursementRateFor = (item: Item): number =>
112	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
113	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
114	    : FULL_REIMBURSEMENT_RATE;
115	
116	const insuranceValueFor = (item: Item): number =>
117	  INSURANCE_VALUE_BY_TYPE[item.type];
118	
119	const policyCoverageCap = (items: Item[]): number =>
120	  CAP_MULTIPLIER * sumBy(items, insuranceValueFor);
121	
122	const findInsuredItem = (items: Item[], itemType: string): Item =>
123	  items.find((item) => item.type === itemType)!;
124	
125	const payoutFor = (item: Item, damage: Damage): number =>
126	  damage.amount * reimbursementRateFor(item) - DEDUCTIBLE;
127	
128	export const claim = (input: ClaimInput): ClaimResult => {
129	  const rawPayout = sumBy(input.incident.damages, (damage) =>
130	    payoutFor(findInsuredItem(input.policy.items, damage.itemType), damage),
131	  );
132	  const cap = policyCoverageCap(input.policy.items);
133	  const payout = Math.min(rawPayout, cap);
134	  return { payout, remainingCap: cap - payout };
135	};
